for (int i=-7; i<3; ++i) {
draw((i,-0.2)--(i,0.2));
draw((-0.2,i)--(0.2,i));
}
draw((-7,1)--(1,-7),linewidth(1));
draw((1,1)--(-7,-7),linewidth(1));
draw((-8,0)--(3,0),Arrow);
draw((0,-8)--(0,3),Arrow);
